import React from 'react';
import { Product } from '../data/products';

// ProductCard component: Displays individual product information in a card format
// Props: product - The product object to display
// This component is reusable and styled to match Flipkart's product card design
interface ProductCardProps {
  product: Product;
}

const ProductCard: React.FC<ProductCardProps> = ({ product }) => {
  // Calculate discount percentage if original price exists
  const discount = product.originalPrice
    ? Math.round(((product.originalPrice - product.price) / product.originalPrice) * 100)
    : 0;

  return (
    // Card container with shadow, border, and hover effects
    <div className="bg-white border border-gray-200 rounded-lg p-4 shadow-sm hover:shadow-md transition-shadow duration-200">
      {/* Product image container */}
      <div className="aspect-square mb-4 overflow-hidden rounded-lg">
        <img
          src={product.image}
          alt={product.name}
          className="w-full h-full object-cover hover:scale-105 transition-transform duration-200"
        />
      </div>

      {/* Product name - truncated if too long */}
      <h3 className="text-lg font-medium text-gray-900 mb-2 line-clamp-2">
        {product.name}
      </h3>

      {/* Rating and reviews */}
      <div className="flex items-center mb-2">
        <div className="flex items-center">
          {/* Star rating display */}
          <span className="text-yellow-400 text-sm">★</span>
          <span className="text-sm text-gray-600 ml-1">
            {product.rating} ({product.reviews})
          </span>
        </div>
      </div>

      {/* Price section */}
      <div className="flex items-center gap-2 mb-2">
        <span className="text-xl font-bold text-gray-900">
          ₹{product.price.toLocaleString()}
        </span>
        {product.originalPrice && (
          <>
            <span className="text-sm text-gray-500 line-through">
              ₹{product.originalPrice.toLocaleString()}
            </span>
            <span className="text-sm text-green-600 font-medium">
              {discount}% off
            </span>
          </>
        )}
      </div>

      {/* Stock status */}
      <div className="text-sm text-gray-600">
        {product.stock > 0 ? (
          <span className="text-green-600">In stock</span>
        ) : (
          <span className="text-red-600">Out of stock</span>
        )}
      </div>
    </div>
  );
};

export default ProductCard;
